55	const BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	};
62	
63	const COMPONENT_PRICE = 25;
64	const BLOCK_SIZE = 3;
65	const BLOCK_PRICE = 60;
66	const COMPONENT_TYPES = new Set(["rune"]);
67	
68	const FIRST_INSURANCE_SURCHARGE = 1.1;
69	const PROCESSING_FEE = 5;
70	const FLOAT_PRECISION_DIGITS = 6;
71	
72	const componentBase = (count: number): number => {
73	  const blocks = Math.floor(count / BLOCK_SIZE);
74	  const singles = count % BLOCK_SIZE;
75	  return blocks * BLOCK_PRICE + singles * COMPONENT_PRICE;
76	};
77	
78	const countByType = (items: Item[]): Map<string, number> => {
79	  const counts = new Map<string, number>();
80	  for (const item of items) {
81	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
82	  }
83	  return counts;
84	};
85	
86	const itemBaseTotal = (items: Item[]): number => {
87	  let total = 0;
88	  for (const [type, count] of countByType(items)) {
89	    total += COMPONENT_TYPES.has(type)
90	      ? componentBase(count)
91	      : BASE_PREMIUM[type] * count;
92	  }
93	  return total;
94	};
95	
96	const quotePremium = (step: QuoteStep): number => {
97	  const itemTotal = itemBaseTotal(step.items) * FIRST_INSURANCE_SURCHARGE;
98	  const premium = itemTotal + PROCESSING_FEE;
99	  return Math.ceil(Number(premium.toFixed(FLOAT_PRECISION_DIGITS)));
100	};
101	
102	export const runScenario = (scenario: Scenario): ScenarioResult => {
103	  return {
104	    results: scenario.steps.map((step) => ({
105	      premium: quotePremium(step as QuoteStep),
106	    })),
107	  };
108	};
